import React, { useState } from 'react';
import { ApiConnection, ApiVariable, ApiArgument, DataConnection } from '../../types';

// Simple API Templates for common use cases
const apiTemplates = {
    'basic-get': {
        name: 'Basic GET Request',
        description: 'Simple GET request',
        url: 'https://api.example.com/data',
        method: 'GET',
        headers: { 'Accept': 'application/json' },
        params: {},
        arguments: [],
        trigger: { type: 'cyclic', interval: 30000 },
        sampleResponse: '{"id": 1, "name": "Sample", "value": 42}',
        variables: [
            { id: 'var-1', name: 'sampleValue', jsonPath: 'value', type: 'number', description: 'Sample value' }
        ]
    },
    'basic-post': {
        name: 'Basic POST Request', 
        description: 'Simple POST request',
        url: 'https://api.example.com/data',
        method: 'POST',
        headers: { 'Accept': 'application/json', 'Content-Type': 'application/json' },
        params: {},
        arguments: [
            { id: 'arg-1', name: 'data', type: 'static', value: 'test', description: 'Data to send' }
        ],
        trigger: { type: 'conditional', condition: { variable: 'sendData', operator: '==', value: true } },
        sampleResponse: '{"success": true, "id": 123}',
        variables: [
            { id: 'var-1', name: 'success', jsonPath: 'success', type: 'boolean', description: 'Success status' }
        ]
    },
    'basic-put': {
        name: 'Basic PUT Request',
        description: 'Simple PUT request', 
        url: 'https://api.example.com/data',
        method: 'PUT',
        headers: { 'Accept': 'application/json', 'Content-Type': 'application/json' },
        params: {},
        arguments: [
            { id: 'arg-1', name: 'id', type: 'variable', value: 'recordId', description: 'Record ID' }
        ],
        trigger: { type: 'conditional', condition: { variable: 'updateTrigger', operator: '==', value: true } },
        sampleResponse: '{"success": true, "updated": true}',
        variables: [
            { id: 'var-1', name: 'updated', jsonPath: 'updated', type: 'boolean', description: 'Update status' }
        ]
    },
    's7-read': {
        name: 'S7 PLC Read',
        description: 'Read from Siemens S7 PLC',
        url: 'https://192.168.0.1/awp/plc/api/read',
        method: 'GET',
        headers: { 'Accept': 'application/json' },
        params: { 'var': 'DB1.DBD0,DB1.DBX8.0' },
        arguments: [
            { id: 'arg-1', name: 'var', type: 'static', value: 'DB1.DBD0,DB1.DBX8.0', description: 'Variables to read' }
        ],
        trigger: { type: 'cyclic', interval: 1000 },
        sampleResponse: '{"variables": {"DB1.DBD0": {"val": 25.5}, "DB1.DBX8.0": {"val": true}}}',
        variables: [
            { id: 'var-1', name: 'temperature', jsonPath: 'variables["DB1.DBD0"].val', type: 'number', description: 'Temperature' },
            { id: 'var-2', name: 'motorStatus', jsonPath: 'variables["DB1.DBX8.0"].val', type: 'boolean', description: 'Motor status' }
        ]
    },
    's7-write': {
        name: 'S7 PLC Write',
        description: 'Write to Siemens S7 PLC',
        url: 'https://192.168.0.1/awp/plc/api/write',
        method: 'POST',
        headers: { 'Accept': 'application/json', 'Content-Type': 'application/json' },
        params: {},
        body: { "variables": { "DB1.DBD0": 30.5, "DB1.DBX8.0": true } },
        arguments: [
            { id: 'arg-1', name: 'DB1.DBD0', type: 'variable', value: 'setpointTemp', description: 'Temperature setpoint' },
            { id: 'arg-2', name: 'DB1.DBX8.0', type: 'variable', value: 'motorStart', description: 'Motor start' }
        ],
        trigger: { type: 'conditional', condition: { variable: 'writeToPlc', operator: '==', value: true } },
        sampleResponse: '{"success": true, "results": {"DB1.DBD0": {"success": true}}}',
        variables: [
            { id: 'var-1', name: 'writeSuccess', jsonPath: 'success', type: 'boolean', description: 'Write success' }
        ]
    }
};

interface DataConnectionsProps {
    dataConnections: DataConnection;
    onDataConnectionsChange: (connections: DataConnection) => void;
}

const DataConnections: React.FC<DataConnectionsProps> = ({
    dataConnections,
    onDataConnectionsChange
}) => {
    const [activeConnection, setActiveConnection] = useState<string | null>(null);
    const [newConnectionName, setNewConnectionName] = useState('');
    const [showAddConnection, setShowAddConnection] = useState(false);

    const handleAddConnection = () => {
        if (!newConnectionName.trim()) return;

        const newConnection: ApiConnection = {
            id: `api-${Date.now()}`,
            name: newConnectionName.trim(),
            url: '',
            method: 'GET',
            headers: {},
            params: {},
            arguments: [],
            trigger: { type: 'cyclic', interval: 5000 },
            sampleResponse: '',
            variables: [],
            enabled: true
        };

        onDataConnectionsChange({
            ...dataConnections,
            apiConnections: [...dataConnections.apiConnections, newConnection]
        });

        setNewConnectionName('');
        setShowAddConnection(false);
        setActiveConnection(newConnection.id);
    };

    const handleDeleteConnection = (connectionId: string) => {
        onDataConnectionsChange({
            ...dataConnections,
            apiConnections: dataConnections.apiConnections.filter(conn => conn.id !== connectionId)
        });
        if (activeConnection === connectionId) {
            setActiveConnection(null);
        }
    };

    const handleUpdateConnection = (connectionId: string, updates: any) => {
        onDataConnectionsChange({
            ...dataConnections,
            apiConnections: dataConnections.apiConnections.map(conn =>
                conn.id === connectionId ? { ...conn, ...updates } : conn
            )
        });
    };

    const activeConnectionData = dataConnections.apiConnections.find(c => c.id === activeConnection);

    return (
        <div style={{ padding: '20px', height: '100%', overflow: 'auto' }}>
            <div style={{ marginBottom: '20px' }}>
                <h3 style={{ margin: '0 0 15px 0', color: '#343a40' }}>Data Connections</h3>
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: '200px 1fr', gap: '20px', height: 'calc(100% - 80px)' }}>
                {/* Left Panel */}
                <div style={{ backgroundColor: '#f8f9fa', borderRadius: '5px', padding: '15px', overflow: 'auto' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '15px' }}>
                        <h4 style={{ margin: 0, fontSize: '14px' }}>Connections</h4>
                        <button
                            onClick={() => setShowAddConnection(!showAddConnection)}
                            style={{
                                padding: '4px 8px',
                                fontSize: '11px',
                                backgroundColor: '#28a745',
                                color: 'white',
                                border: 'none',
                                borderRadius: '3px',
                                cursor: 'pointer'
                            }}
                        >
                            + Add
                        </button>
                    </div>

                    {showAddConnection && (
                        <div style={{ marginBottom: '15px', padding: '10px', backgroundColor: 'white', borderRadius: '3px' }}>
                            <input
                                type="text"
                                placeholder="Connection name"
                                value={newConnectionName}
                                onChange={(e) => setNewConnectionName(e.target.value)}
                                style={{
                                    width: '100%',
                                    padding: '5px',
                                    fontSize: '11px',
                                    border: '1px solid #ced4da',
                                    borderRadius: '3px',
                                    marginBottom: '8px'
                                }}
                            />
                            <div style={{ display: 'flex', gap: '5px' }}>
                                <button onClick={handleAddConnection} style={{ padding: '4px 8px', fontSize: '10px', backgroundColor: '#007bff', color: 'white', border: 'none', borderRadius: '2px', cursor: 'pointer' }}>
                                    Create
                                </button>
                                <button onClick={() => setShowAddConnection(false)} style={{ padding: '4px 8px', fontSize: '10px', backgroundColor: '#6c757d', color: 'white', border: 'none', borderRadius: '2px', cursor: 'pointer' }}>
                                    Cancel
                                </button>
                            </div>
                        </div>
                    )}

                    {/* Templates */}
                    <div style={{ marginBottom: '20px' }}>
                        <h5 style={{ fontSize: '12px', margin: '0 0 10px 0', color: '#495057' }}>Templates</h5>
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '5px' }}>
                            {Object.entries(apiTemplates).map(([key, template]) => (
                                <button
                                    key={key}
                                    onClick={() => {
                                        const newConnection = {
                                            id: `api-${Date.now()}`,
                                            name: template.name,  
                                            url: template.url,
                                            method: template.method,
                                            headers: template.headers || {},
                                            params: template.params || {},
                                            body: template.body || undefined,
                                            arguments: template.arguments || [],
                                            trigger: template.trigger,
                                            sampleResponse: template.sampleResponse || '',
                                            variables: template.variables || [],
                                            enabled: true
                                        };
                                        
                                        onDataConnectionsChange({
                                            ...dataConnections,
                                            apiConnections: [...dataConnections.apiConnections, newConnection]
                                        });
                                        setActiveConnection(newConnection.id);
                                    }}
                                    style={{
                                        padding: '6px 8px',
                                        fontSize: '10px',
                                        backgroundColor: 'white',
                                        border: '1px solid #dee2e6',
                                        borderRadius: '3px',
                                        cursor: 'pointer',
                                        textAlign: 'left'
                                    }}
                                >
                                    {template.name}
                                </button>
                            ))}
                        </div>
                    </div>

                    {/* Connections List */}
                    <div>
                        {dataConnections.apiConnections.map(connection => (
                            <div
                                key={connection.id}
                                style={{
                                    padding: '8px',
                                    backgroundColor: activeConnection === connection.id ? '#007bff' : 'white',
                                    color: activeConnection === connection.id ? 'white' : 'black',
                                    borderRadius: '3px',
                                    cursor: 'pointer',
                                    marginBottom: '5px',
                                    fontSize: '11px',
                                    display: 'flex',
                                    justifyContent: 'space-between',
                                    alignItems: 'center'
                                }}
                                onClick={() => setActiveConnection(connection.id)}
                            >
                                <span>{connection.name}</span>
                                <button
                                    onClick={(e) => {
                                        e.stopPropagation();
                                        handleDeleteConnection(connection.id);
                                    }}
                                    style={{
                                        padding: '2px 5px',
                                        fontSize: '10px',
                                        backgroundColor: 'transparent',
                                        color: activeConnection === connection.id ? 'white' : '#dc3545',
                                        border: 'none',
                                        cursor: 'pointer'
                                    }}
                                >
                                    ×
                                </button>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Right Panel */}
                <div style={{ backgroundColor: 'white', borderRadius: '5px', padding: '20px', overflow: 'auto' }}>
                    {activeConnectionData ? (
                        <div>
                            <h4 style={{ margin: '0 0 20px 0', fontSize: '16px' }}>{activeConnectionData.name}</h4>
                            
                            {/* URL */}
                            <div style={{ marginBottom: '15px' }}>
                                <label style={{ fontSize: '12px', fontWeight: 'bold', display: 'block', marginBottom: '5px' }}>URL:</label>
                                <input
                                    type="text"
                                    value={activeConnectionData.url}
                                    onChange={(e) => handleUpdateConnection(activeConnectionData.id, { url: e.target.value })}
                                    style={{ width: '100%', padding: '6px', fontSize: '12px', border: '1px solid #ced4da', borderRadius: '3px' }}
                                />
                            </div>

                            {/* Method */}
                            <div style={{ marginBottom: '15px' }}>
                                <label style={{ fontSize: '12px', fontWeight: 'bold', display: 'block', marginBottom: '5px' }}>Method:</label>
                                <select
                                    value={activeConnectionData.method}
                                    onChange={(e) => {
                                        handleUpdateConnection(activeConnectionData.id, { method: e.target.value });
                                    }}
                                    style={{ padding: '6px', fontSize: '12px', border: '1px solid #ced4da', borderRadius: '3px' }}
                                >
                                    <option value="GET">GET</option>
                                    <option value="POST">POST</option>
                                    <option value="PUT">PUT</option>
                                    <option value="DELETE">DELETE</option>
                                </select>
                            </div>

                            {/* Sample Response */}
                            <div style={{ marginBottom: '15px' }}>
                                <label style={{ fontSize: '12px', fontWeight: 'bold', display: 'block', marginBottom: '5px' }}>Sample Response:</label>
                                <textarea
                                    placeholder='{"name": "John", "age": 30}'
                                    value={activeConnectionData.sampleResponse}
                                    onChange={(e) => handleUpdateConnection(activeConnectionData.id, { sampleResponse: e.target.value })}
                                    style={{
                                        width: '100%',
                                        height: '100px',
                                        padding: '6px',
                                        fontSize: '11px',
                                        fontFamily: 'monospace',
                                        border: '1px solid #ced4da',
                                        borderRadius: '3px',
                                        resize: 'vertical'
                                    }}
                                />
                            </div>
                        </div>
                    ) : (
                        <div style={{ textAlign: 'center', color: '#6c757d', marginTop: '50px' }}>
                            <p>Select a connection from the left panel or create a new one</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

export default DataConnections;
